        api: 'API\u914D\u7F6E',
        source: '\u6E90\u914D\u7F6E',
        match: '\u5339\u914D\u914D\u7F6E',
        danmu: '\u5F39\u5E55\u914D\u7F6E',
        cache: '\u7F13\u5B58\u914D\u7F6E',
